<template>
  <u-popup :show="show" mode="bottom" round="20" @close="handleClose">
    <view class="popup-wrap">
      <view class="popup-header">
        <text class="popup-title">筛选</text>
      </view>

      <scroll-view scroll-y class="popup-content">
        <!-- 病种 -->
        <view class="section">
          <view class="section-title">病种</view>

          <view
            v-for="group in diseaseGroups"
            :key="group.id"
            class="group-block"
          >
            <view class="group-title">{{ group.name }}</view>
            <view class="tag-list">
              <view
                v-for="item in group.children"
                :key="item.id"
                class="tag-item"
                :class="{ active: innerForm.diseaseId === item.id }"
                @click="selectDisease(item)"
              >
                {{ item.name }}
              </view>
            </view>
          </view>
        </view>

        <!-- 地区 -->
        <view class="section">
          <view class="section-title">地区</view>
          <RegionPicker
            v-model="innerForm.region"
            placeholder="全部地区"
          />
        </view>

        <!-- 职称 -->
        <view class="section">
          <view class="section-title">职称</view>
          <view class="tag-list">
            <view
              v-for="item in titleOptions"
              :key="item.value"
              class="tag-item"
              :class="{ active: innerForm.title === item.value }"
              @click="innerForm.title = item.value"
            >
              {{ item.label }}
            </view>
          </view>
        </view>

        <!-- 医院 -->
        <view class="section">
          <view class="section-title">医院</view>
          <HospitalPicker
            v-model="innerForm.hospital"
          />
        </view>
      </scroll-view>

      <view class="popup-footer">
        <u-button
          text="重置"
          shape="circle"
          color="#f3f4f6"
          customStyle="color:#606266"
          @click="handleReset"
        />
        <u-button
          text="确定"
          type="primary"
          shape="circle"
          @click="handleConfirm"
        />
      </view>
    </view>
  </u-popup>
</template>

<script setup lang="ts">
import { ref, watch } from 'vue'
import RegionPicker from '@/components/RegionPicker.vue'
import HospitalPicker from './HospitalPicker.vue'

export interface FilterForm {
  diseaseId: number | string | ''
  diseaseName: string
  title: string
  region: {
    provinceCode?: string
    provinceName?: string
    cityCode?: string
    cityName?: string
    districtCode?: string
    districtName?: string
  }
  hospital: {
    hospitalId?: number | string | ''
    hospitalName?: string
  }
}

const props = withDefaults(defineProps<{
  show: boolean
  modelValue?: Partial<FilterForm>
}>(), {
  modelValue: () => ({})
})

const emit = defineEmits<{
  (e: 'update:show', value: boolean): void
  (e: 'update:modelValue', value: FilterForm): void
  (e: 'confirm', value: FilterForm): void
  (e: 'reset'): void
}>()

const diseaseGroups = ref([
  {
    id: 1,
    name: '神经系统',
    children: [
      { id: 5, name: '脊髓性肌萎缩症' }
    ]
  },
  {
    id: 2,
    name: '代谢类',
    children: [
      { id: 1, name: '法布雷病' },
      { id: 2, name: '戈谢病' },
      { id: 6, name: '低磷性佝偻病' }
    ]
  },
  {
    id: 3,
    name: '免疫类',
    children: []
  }
])

const titleOptions = [
  { label: '全部', value: '' },
  { label: '主任医师', value: '主任医师' },
  { label: '副主任医师', value: '副主任医师' },
  { label: '主治医师', value: '主治医师' }
]

const getDefaultForm = (): FilterForm => ({
  diseaseId: '',
  diseaseName: '',
  title: '',
  region: {
    provinceCode: '',
    provinceName: '',
    cityCode: '',
    cityName: '',
    districtCode: '',
    districtName: ''
  },
  hospital: {
    hospitalId: '',
    hospitalName: ''
  }
})

const innerForm = ref<FilterForm>(getDefaultForm())

watch(
  () => props.show,
  (val) => {
    if (val) {
      innerForm.value = {
        ...getDefaultForm(),
        ...props.modelValue,
        region: {
          ...getDefaultForm().region,
          ...(props.modelValue?.region || {})
        },
        hospital: {
          ...getDefaultForm().hospital,
          ...(props.modelValue?.hospital || {})
        }
      }
    }
  },
  { immediate: true }
)

const selectDisease = (item: { id: number | string, name: string }) => {
  innerForm.value.diseaseId = item.id
  innerForm.value.diseaseName = item.name
}

const handleClose = () => {
  emit('update:show', false)
}

const handleReset = () => {
  innerForm.value = getDefaultForm()
  emit('update:modelValue', innerForm.value)
  emit('reset')
}

const handleConfirm = () => {
  emit('update:modelValue', innerForm.value)
  emit('confirm', innerForm.value)
  emit('update:show', false)
}
</script>

